def invertTree(self, root):
    if not root:
        return None
    root.left, root.right = self.invertTree(root.right), self.invertTree(root.left)
    return root

def invertTree_bfs(self, root):
    if not root:
        return None
    q = deque([root])
    while q:
        n = q.popleft()
        n.left, n.right = n.right, n.left
        if n.left:
            q.append(n.left)
        if n.right:
            q.append(n.right)
    return root
